mapper.select:
select
ci.id as info_id,
ci.course_id as info_course_id,
ci.teacher_id as info_teacher_id,
ci.course_date as info_course_date,
ci.course_period as info_course_period,
ci.course_address as info_course_address,
ci.max_number as info_max_number,

c.id as c_id,
c.course_id as c_course_id,
c.course_name as c_course_name,
c.credits as c_credits,
c.description as c_description,

t.id as t_id,
t.teacher_id as t_teacher_id,
t.name as t_name,
t.gender as t_gender

from cms_course_info ci
left join cms_course c on ci.course_id = c.id
left join cms_teacher t on ci.teacher_id = t.id


        and ci.id = #{id}



        and ci.course_id like #{courseIdLike}



        and ci.teacher_id like #{teacherIdLike}


        and ci.course_date = #{courseDate}


        and ci.course_period = #{coursePeriod}



        and ci.course_address like #{courseAddressLike}



        and c.course_name like #{courseNameLike}



        and t.name like #{nameLike}



        and c.course_id like #{courseIdLike}



        and t.teacher_id like #{teacherIdLike}

select *
from cms_course_info
where id = #{id}
limit 1;
